UPDATE scheduled_emails AS se
SET status = 'processing',
    attempt_count = se.attempt_count + 1,
    last_attempt_at = #{now},
    updated_at = #{now}
FROM (
    SELECT id
    FROM scheduled_emails
    WHERE deleted_at IS NULL
      AND tenant_id = #{tenantId}
      AND status IN ('scheduled', 'failed')
      AND scheduled_at <= #{now}
      AND attempt_count < 3
      AND (
        status = 'scheduled'
        OR (
          status = 'failed'
          AND (
            last_attempt_at IS NULL
            OR last_attempt_at + (
              POWER(2::numeric, GREATEST(attempt_count - 1, 0))::int * INTERVAL '1 minute'
            ) <= #{now}
          )
        )
      )
    ORDER BY scheduled_at
    LIMIT #{limit}
    FOR UPDATE SKIP LOCKED
) AS picked
WHERE se.id = picked.id
RETURNING se.*

SELECT COALESCE(
    EXTRACT(EPOCH FROM (#{now} - MIN(scheduled_at))),
    0
)
FROM scheduled_emails
WHERE deleted_at IS NULL
  AND tenant_id = #{tenantId}
  AND status = 'scheduled'
  AND scheduled_at <= #{now}
